mcqs.question:
What will be the output of the following code?
int i = 0;
while(i < 3) {
 System.out.print(i + " ");
 i++;
}

What is the output?
for(int i = 5; i > 0; i--) {
 System.out.print(i + " ");
}

What is the output?
int count = 0;
for(int i = 0; i < 5; i++) {
 if(i == 2) continue;
 count++;
}
System.out.println(count);

What is the output?
int i = 1;
do {
 System.out.print(i + " ");
 i++;
} while(i <= 3);

What is the output?
outer: for(int i = 0; i < 2; i++) {
 for(int j = 0; j < 2; j++) {
 if(j == 0) break outer;
 System.out.print(j);
 }
}
System.out.println("Done");

How many times will 'Hello' be printed?
for(int i = 0; i < 10; i++) {
 if(i % 2 == 0) continue;
 System.out.println("Hello");
}

What is the output?
int sum = 0;
for(int i = 1; i <= 5; i++) {
 sum += i;
}
System.out.println(sum);

What is the output?
int i = 0;
while(i < 3) {
 System.out.print(i);
 if(i == 1) break;
 i++;
}
